// ════════════════════════════════════════════════════
// SOUND ENGINE
// ════════════════════════════════════════════════════
let audioCtx = null;
let soundEnabled = true;

function getAC(){
  if(!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  return audioCtx;
}

function playNote(freq, dur, vol=0.16, delay=0){
  if(!soundEnabled) return;
  try{
    const ac = getAC();
    const t = ac.currentTime + delay;
    const osc = ac.createOscillator();
    const gain = ac.createGain();
    const filt = ac.createBiquadFilter();
    filt.type='lowpass'; filt.frequency.value=freq*4; filt.Q.value=0.4;
    osc.type='sine'; osc.frequency.setValueAtTime(freq, t);
    gain.gain.setValueAtTime(0.001,t);
    gain.gain.linearRampToValueAtTime(vol,t+0.025);
    gain.gain.setValueAtTime(vol,t+dur*0.65);
    gain.gain.exponentialRampToValueAtTime(0.001,t+dur);
    osc.connect(filt); filt.connect(gain); gain.connect(ac.destination);
    osc.start(t); osc.stop(t+dur+0.05);
  }catch(e){}
}

const SFX = {
  typeChar(){ if(Math.random()>0.90) playNote(200+Math.random()*60,0.05,0.04); },
  nextScene(){ playNote(196,0.18,0.15,0); playNote(247,0.18,0.15,0.1); playNote(294,0.25,0.17,0.2); },
  tabSwitch(){ playNote(220,0.14,0.13,0); playNote(262,0.18,0.13,0.09); },
  victory(){ [196,247,294,392].forEach((f,i)=>playNote(f,0.3,0.13,i*0.11)); playNote(392,0.5,0.12,0.5); },
  bulb(){ playNote(330,0.15,0.12,0); playNote(415,0.15,0.12,0.12); playNote(494,0.22,0.14,0.24); },
  dlgOpen(){ playNote(196,0.18,0.14,0); playNote(247,0.22,0.14,0.12); },
  boot(){ [130,164,196,220,262,330].forEach((f,i)=>playNote(f,0.18,0.11,i*0.13)); },
  nav(){ playNote(262,0.12,0.1,0); }
};

window.toggleSound = function(){
  soundEnabled = !soundEnabled;
  const btn = document.getElementById('sound-btn');
  btn.textContent = soundEnabled ? '🔊 SON ON' : '🔇 SON OFF';
  btn.classList.toggle('muted', !soundEnabled);
  if(soundEnabled) playNote(262,0.15,0.13);
};

// ════════════════════════════════════════════════════
// SPRITE RENDERERS
// ════════════════════════════════════════════════════
function drawRLE(ctx, rows, cw, ch){
  ctx.clearRect(0,0,cw,ch);
  const sx=cw/SW, sy=ch/SH;
  rows.forEach((row,y)=>{
    row.forEach(([x,w,color])=>{
      ctx.fillStyle=color;
      ctx.fillRect(Math.round(x*sx),Math.round(y*sy),Math.ceil(w*sx),Math.ceil(sy)+1);
    });
  });
}

function drawMouth(ctx, mouth, cw, ch){
  const sx=cw/SW, sy=ch/SH;
  ctx.fillStyle='rgba(20,6,6,0.9)';
  ctx.fillRect(Math.round(mouth.x*sx),Math.round(mouth.y*sy),Math.round(mouth.w*sx),Math.round(sy*1.6));
  ctx.fillStyle='rgba(140,60,55,0.45)';
  ctx.fillRect(Math.round((mouth.x-0.5)*sx),Math.round(mouth.y*sy),Math.round((mouth.w+1)*sx),Math.round(sy*0.5));
}

function drawSanae(ctx,cw,ch,variant){ drawRLE(ctx,SANAE_ROWS,cw,ch); if(variant==='talk') drawMouth(ctx,MOUTHS.sanae,cw,ch); }
function drawRec(ctx,cw,ch,variant){ drawRLE(ctx,REC_ROWS,cw,ch); if(variant==='talk') drawMouth(ctx,MOUTHS.rec,cw,ch); }
function drawNPC1(ctx,cw,ch,variant){ drawRLE(ctx,NPC_REC1_ROWS,cw,ch); if(variant==='talk') drawMouth(ctx,MOUTHS.rec,cw,ch); }
function drawNPC2(ctx,cw,ch,variant){ drawRLE(ctx,NPC_REC2_ROWS,cw,ch); if(variant==='talk') drawMouth(ctx,MOUTHS.rec,cw,ch); }

function drawByType(ctx,cw,ch,type,variant){
  switch(type){
    case 'sanae': drawSanae(ctx,cw,ch,variant); break;
    case 'rec':   drawRec(ctx,cw,ch,variant); break;
    case 'npc1':  drawNPC1(ctx,cw,ch,variant); break;
    case 'npc2':  drawNPC2(ctx,cw,ch,variant); break;
  }
}

function setupCanvas(el,cw,ch){ el.width=cw; el.height=ch; return el.getContext('2d'); }

function initAllCanvases(){
  [['c-sanae-hero',120,168],['c-sanae-about',100,140],['c-sanae-exp',100,140],['c-sanae-con',120,168]].forEach(([id,cw,ch])=>{
    const el=document.getElementById(id); if(!el)return;
    drawSanae(setupCanvas(el,cw,ch),cw,ch,'neutral');
  });
  const bc=document.getElementById('boot-char');
  if(bc) drawSanae(setupCanvas(bc,120,168),120,168,'neutral');
  [['c-rec-hero',120,168],['c-rec-con',120,168]].forEach(([id,cw,ch])=>{
    const el=document.getElementById(id); if(!el)return;
    drawRec(setupCanvas(el,cw,ch),cw,ch,'neutral');
  });
}

// ════════════════════════════════════════════════════
// TALK ANIMATION
// ════════════════════════════════════════════════════
const TALKTIMERS={};
function startTalk(el,type){
  if(!el)return;
  const id=el.id; if(TALKTIMERS[id]) clearInterval(TALKTIMERS[id]);
  let f=0;
  TALKTIMERS[id]=setInterval(()=>{
    const ctx=el.getContext('2d');
    drawByType(ctx,el.width,el.height,type,f%2===0?'talk':'neutral');
    f++;
  },220);
}
function stopTalk(el,type){
  if(!el)return;
  const id=el.id;
  if(TALKTIMERS[id]){clearInterval(TALKTIMERS[id]);delete TALKTIMERS[id];}
  drawByType(el.getContext('2d'),el.width,el.height,type,'neutral');
}

