// SCENE BACKGROUNDS
// ════════════════════════════════════════════════════
function drawSceneBg(canvas, variant){
  const W=1100,H=380;
  canvas.width=W; canvas.height=H;
  const ctx=canvas.getContext('2d');
  ctx.clearRect(0,0,W,H);
  const wg=ctx.createLinearGradient(0,0,0,H);
  if(variant==='lab'){wg.addColorStop(0,'#030412');wg.addColorStop(1,'#060622');}
  else{wg.addColorStop(0,'#050519');wg.addColorStop(1,'#090920');}
  ctx.fillStyle=wg; ctx.fillRect(0,0,W,H);
  ctx.strokeStyle='rgba(124,58,237,0.055)'; ctx.lineWidth=1;
  for(let x=0;x<W;x+=40){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();}
  for(let y=0;y<H;y+=40){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
  const fg=ctx.createLinearGradient(0,H-72,0,H);
  fg.addColorStop(0,'#0d0d26');fg.addColorStop(1,'#070718');
  ctx.fillStyle=fg; ctx.fillRect(0,H-72,W,72);
  ctx.fillStyle='rgba(124,58,237,0.2)'; ctx.fillRect(0,H-73,W,2);
  for(let i=0;i<3;i++){
    const wx=80+i*340,wy=28,ww=130,wh=108;
    ctx.fillStyle='#060820'; ctx.fillRect(wx,wy,ww,wh);
    ctx.strokeStyle='#1c1c3e'; ctx.lineWidth=4; ctx.strokeRect(wx,wy,ww,wh);
    const wgrad=ctx.createLinearGradient(wx,wy,wx,wy+wh);
    wgrad.addColorStop(0,'rgba(60,120,180,0.12)');wgrad.addColorStop(1,'transparent');
    ctx.fillStyle=wgrad; ctx.fillRect(wx,wy,ww,wh);
    ctx.fillStyle='#1c1c3e';
    ctx.fillRect(wx+ww/2-1,wy,2,wh); ctx.fillRect(wx,wy+wh/2-1,ww,2);
  }
  if(['office','office-problem','office-victory','meeting'].includes(variant)){
    ctx.fillStyle='#311a0a'; ctx.fillRect(160,H-162,780,22);
    ctx.fillStyle='#5a3a20'; ctx.fillRect(160,H-164,780,4);
    [[180,H-140],[900,H-140]].forEach(([x,y])=>{ctx.fillStyle='#2a1408';ctx.fillRect(x,y,12,52);});
    ctx.fillStyle='#040408'; ctx.fillRect(470,H-248,100,78);
    ctx.fillStyle='#1e1e3e'; ctx.fillRect(468,H-172,104,8);
    ctx.fillStyle='rgba(6,182,212,0.10)'; ctx.fillRect(474,H-246,92,72);
    [[0,'rgba(184,244,0,0.5)'],[1,'rgba(124,58,237,0.5)'],[2,'rgba(6,182,212,0.5)']].forEach(([i,c])=>{
      const bh=18+Math.sin(i*2.1)*12+8;
      ctx.fillStyle=c; ctx.fillRect(482+i*24,H-176-bh,17,bh);
    });
  }
  if(variant==='pc-work'){
    ctx.fillStyle='#311a0a'; ctx.fillRect(250,H-158,600,20);
    ctx.fillStyle='#5a3a20'; ctx.fillRect(250,H-160,600,4);
    ctx.fillStyle='#020206'; ctx.fillRect(375,H-300,230,134);
    ctx.fillStyle='#333'; ctx.fillRect(373,H-168,234,8);
    ctx.fillStyle='#1a1a35'; ctx.fillRect(460,H-168,60,8);
    const sg=ctx.createRadialGradient(490,H-235,5,490,H-235,130);
    sg.addColorStop(0,'rgba(184,244,0,0.10)');sg.addColorStop(1,'transparent');
    ctx.fillStyle=sg; ctx.fillRect(379,H-298,222,128);
    ctx.font='8px monospace';
    [['rgba(184,244,0,0.85)','class SAPIntelligentOCR:'],
     ['rgba(6,182,212,0.75)','  def scan_screen(self):'],
     ['rgba(255,255,255,0.40)','    data = pytesseract.image_to_data('],
     ['rgba(124,58,237,0.85)','    # Localise chaque champ...'],
     ['rgba(184,244,0,0.75)','  def fill_field(self, label, val):'],
     ['rgba(6,182,212,0.65)','    pos = self.ocr_find(label)'],
     ['rgba(255,255,255,0.35)','    pyautogui.click(*pos)'],
     ['rgba(236,72,153,0.70)','  # Export → SharePoint ✓'],
    ].forEach(([c,t],i)=>{ctx.fillStyle=c;ctx.fillText(t,385,H-285+i*15);});
    ctx.fillStyle='rgba(25,25,55,0.8)'; ctx.fillRect(340,H-145,310,26);
    for(let k=0;k<13;k++){ctx.fillStyle='rgba(255,255,255,0.05)';ctx.fillRect(348+k*22,H-140,18,10);}
  }
  if(variant==='lab'){
    for(let i=0;i<3;i++){
      const sx=100+i*320,sy=H-298;
      ctx.fillStyle='#010a14'; ctx.fillRect(sx,sy,210,168);
      ctx.strokeStyle='#0a2535'; ctx.lineWidth=2; ctx.strokeRect(sx,sy,210,168);
      ctx.fillStyle='rgba(80,160,220,0.05)'; ctx.fillRect(sx+4,sy+4,202,160);
      ctx.fillStyle='rgba(170,205,245,0.16)';
      ctx.beginPath();ctx.ellipse(sx+68,sy+95,36,54,0,0,Math.PI*2);ctx.fill();
      ctx.beginPath();ctx.ellipse(sx+142,sy+95,36,54,0,0,Math.PI*2);ctx.fill();
      ctx.fillStyle='rgba(236,72,153,0.65)';
      ctx.beginPath();ctx.arc(sx+72,sy+82,5,0,Math.PI*2);ctx.fill();
      ctx.strokeStyle='rgba(236,72,153,0.85)';ctx.lineWidth=1;
      ctx.beginPath();ctx.arc(sx+72,sy+82,9,0,Math.PI*2);ctx.stroke();
    }
  }
  if(variant==='office-victory'){
    for(let i=0;i<22;i++){
      const px=60+Math.random()*(W-120),py=20+Math.random()*200;
      ctx.fillStyle=`hsla(${40+Math.random()*80},100%,65%,0.85)`;
      ctx.beginPath();ctx.arc(px,py,1.5+Math.random()*2,0,Math.PI*2);ctx.fill();
    }
    const vg=ctx.createRadialGradient(W/2,H,0,W/2,H,280);
    vg.addColorStop(0,'rgba(184,244,0,0.05)');vg.addColorStop(1,'transparent');
    ctx.fillStyle=vg; ctx.fillRect(0,0,W,H);
  }
}

