const sceneState={0:0,1:0,2:0,3:0};
const activeTimers={};

function stopAllSceneTimers(){
  Object.keys(activeTimers).forEach(id=>{clearInterval(activeTimers[id]);delete activeTimers[id];});
}

function createSceneChar(layerEl,charDef){
  const PS=3;
  const cw=Math.round(SW*PS*charDef.scale);
  const ch=Math.round(SH*PS*charDef.scale);
  const wrap=document.createElement('div');
  wrap.style.cssText=`position:absolute;bottom:55px;left:${charDef.x}px;display:flex;flex-direction:column;align-items:center;transition:left .9s cubic-bezier(.4,0,.2,1)`;
  wrap.id=`cw-${charDef.id}`;
  const cv=document.createElement('canvas');
  cv.id=`cc-${charDef.id}`; cv.width=cw; cv.height=ch;
  cv.style.cssText=`width:${cw}px;height:${ch}px;image-rendering:pixelated;display:block`;
  const lbl=document.createElement('div');
  lbl.style.cssText=`font-family:'Press Start 2P',monospace;font-size:5px;color:#b8f400;margin-top:3px;white-space:nowrap;text-shadow:0 0 5px #b8f400`;
  lbl.textContent=charDef.label;
  wrap.appendChild(cv); wrap.appendChild(lbl);
  layerEl.appendChild(wrap);
  drawByType(cv.getContext('2d'),cw,ch,charDef.type,'neutral');
  return cv;
}

function loadScene(p,s){
  const key=`${p}-${s}`;
  const sc=SCRIPTS[p].data[s];
  document.getElementById(`step-${p}`).textContent=sc.step;
  document.getElementById(`spk-${p}`).textContent=sc.spk;
  const txtEl=document.getElementById(`txt-${p}`);
  txtEl.innerHTML='<span class="scene-cur"></span>';
  const msg=sc.txt; let i=0; let typeTimer=null;
  function type(){if(i<msg.length){txtEl.textContent=msg.substring(0,i+1);i++;SFX.typeChar();typeTimer=setTimeout(type,20);}};
  txtEl.onclick=()=>{if(typeTimer){clearTimeout(typeTimer);txtEl.textContent=msg;typeTimer=null;txtEl.onclick=null;}};
  type();
  const imp=document.getElementById(`imp-${p}`);
  const tags=document.getElementById(`tags-${p}`);
  if(imp) imp.style.display=sc.impact?'flex':'none';
  if(tags) tags.style.display=sc.impact?'flex':'none';
  const prog=document.getElementById(`prog-${p}`);
  if(prog)[...prog.children].forEach((d,i)=>{d.className='rpg-dot'+(i<s?' done':i===s?' current':'');});
  document.getElementById(`prev-${p}`).disabled=s===0;
  const nb=document.getElementById(`next-${p}`);
  nb.disabled=s>=SCRIPTS[p].max;
  nb.textContent=s>=SCRIPTS[p].max?'✅ FIN':'SUIVANT ▶';
  const bulb=document.getElementById(`bulb-${p}`);
  if(bulb){const show=s===1&&(p===0||p===1);bulb.classList.toggle('show',show);if(show)setTimeout(()=>SFX.bulb(),200);}
  if(sc.impact) setTimeout(()=>SFX.victory(),600);
  stopAllSceneTimers();
  (CHAR_MAP[key]||[]).forEach(charDef=>{
    const cv=document.getElementById(`cc-${charDef.id}`); if(!cv)return;
    if(charDef.talking){
      let f=0;
      activeTimers[charDef.id]=setInterval(()=>{
        drawByType(cv.getContext('2d'),cv.width,cv.height,charDef.type,f%2===0?'talk':'neutral');
        f++;
      },220);
    }
  });
}

function initRPGScenes(){
  Object.entries(BG_MAP).forEach(([key,variant])=>{
    const [p,s]=key.split('-');
    const bg=document.getElementById(`bg-${p}-${s}`);
    if(bg) drawSceneBg(bg,variant);
    const layer=document.getElementById(`cl-${p}-${s}`);
    if(!layer)return;
    layer.innerHTML='';
    (CHAR_MAP[key]||[]).forEach(charDef=>createSceneChar(layer,charDef));
  });
  loadScene(0,0);
}

window.nextScene = function(p){
  if(sceneState[p]>=SCRIPTS[p].max)return;
  sceneState[p]++;
  const ns=sceneState[p];
  const wrap=document.getElementById(`proj-${p}`).querySelector('.rpg-scenes-wrap');
  [...wrap.children].forEach((el,i)=>el.classList.toggle('current',i===ns));
  loadScene(p,ns); SFX.nextScene();
};
window.prevScene = function(p){
  if(sceneState[p]<=0)return;
  sceneState[p]--;
  const ns=sceneState[p];
  const wrap=document.getElementById(`proj-${p}`).querySelector('.rpg-scenes-wrap');
  [...wrap.children].forEach((el,i)=>el.classList.toggle('current',i===ns));
  loadScene(p,ns);
};

let currentProj=0;
window.switchProject = function(idx){
  document.querySelectorAll('.rpg-scene').forEach((el,i)=>el.classList.toggle('active',i===idx));
  document.querySelectorAll('.proj-tab').forEach((el,i)=>el.classList.toggle('active',i===idx));
  currentProj=idx; sceneState[idx]=0;
  const wrap=document.getElementById(`proj-${idx}`).querySelector('.rpg-scenes-wrap');
  [...wrap.children].forEach((el,i)=>el.classList.toggle('current',i===0));
  loadScene(idx,0); SFX.tabSwitch();
  showNotif(`QUEST ${idx+1} CHARGÉE`);
};

