const DS={};
Object.keys(DLGS).forEach(k=>DS[k]={idx:-1,typing:false,timer:null,started:false});

function updateDlgBtns(key){
  const d=DLGS[key],s=DS[key];
  const prev=document.getElementById(d.prevId),next=document.getElementById(d.nextId),ctr=document.getElementById(d.ctrId);
  if(prev)prev.disabled=s.idx<=0;
  if(next)next.disabled=s.idx>=d.msgs.length-1;
  if(ctr)ctr.textContent=`${s.idx+1} / ${d.msgs.length}`;
}
function typeMsg(key,idx){
  const d=DLGS[key],s=DS[key];
  const txtEl=document.getElementById(d.textId),curEl=d.curId?document.getElementById(d.curId):null;
  if(!txtEl)return;
  clearTimeout(s.timer);s.idx=idx;s.typing=true;
  if(curEl)curEl.style.display='inline-block';
  txtEl.textContent='';
  const charEl=document.getElementById(d.charId);
  if(charEl) startTalk(charEl,d.charType);
  updateDlgBtns(key);
  const msg=d.msgs[idx];let i=0;
  function tick(){
    if(i<msg.length){txtEl.textContent+=msg[i++];SFX.typeChar();s.timer=setTimeout(tick,22);}
    else{s.typing=false;if(curEl)curEl.style.display='none';
      const ce=document.getElementById(d.charId);
      if(ce) stopTalk(ce,d.charType);
      updateDlgBtns(key);}
  }
  tick();
}
window.startDlg = function(key){
  const d=DLGS[key],s=DS[key];
  if(!s.started){s.started=true;
    const p=document.getElementById(d.playId);if(p)p.style.display='none';
    const pv=document.getElementById(d.prevId),nx=document.getElementById(d.nextId);
    if(pv)pv.style.display='flex';if(nx)nx.style.display='flex';}
  SFX.dlgOpen(); typeMsg(key,0);
};
window.nextDlg = function(key){const s=DS[key],d=DLGS[key];if(!s.typing&&s.idx<d.msgs.length-1)typeMsg(key,s.idx+1);};
window.prevDlg = function(key){const s=DS[key];if(!s.typing&&s.idx>0)typeMsg(key,s.idx-1);};

