// BOOT SEQUENCE
// ════════════════════════════════════════════════════
const bootMsgs=['LOADING CHARACTER DATA...','CONNECTING TO SNOWFLAKE DB...','RUNNING ML PIPELINE...','RENDERING PIXEL ART...','READY!'];
let bootPct=0;

function bootTick(){
  bootPct+=Math.random()*12+6; if(bootPct>100)bootPct=100;
  const fill=document.getElementById('boot-fill');
  const msg=document.getElementById('boot-msg');
  if(fill) fill.style.width=bootPct+'%';
  if(msg) msg.textContent=bootMsgs[Math.min(Math.floor(bootPct/25),4)];
  if(bootPct<100){setTimeout(bootTick,120);}
  else{
    const bootEl=document.getElementById('boot');
    setTimeout(()=>{ bootEl.classList.add('hide'); setTimeout(()=>bootEl.remove(),700); },400);
    setTimeout(()=>SFX.boot(),500);
  }
}

// Unlock audio
function unlockAudio(){
  getAC();
  document.removeEventListener('click',unlockAudio);
  document.removeEventListener('keydown',unlockAudio);
}
document.addEventListener('click',unlockAudio);
document.addEventListener('keydown',unlockAudio);

// ════════════════════════════════════════════════════
// CURSOR
// ════════════════════════════════════════════════════
function initCursor(){
  const curDot=document.getElementById('cur'),curRing=document.getElementById('cur2');
  let mx=0,my=0,rx=0,ry=0;
  document.addEventListener('mousemove',e=>{
    mx=e.clientX;my=e.clientY;
    curDot.style.transform=`translate(${mx-3}px,${my-3}px)`;
  },{passive:true});
  (function animCursor(){
    rx+=(mx-rx)*.11;ry+=(my-ry)*.11;
    curRing.style.transform=`translate(${rx-12}px,${ry-12}px)`;
    requestAnimationFrame(animCursor);
  })();
  document.querySelectorAll('a,button,.proj-tab,.skill-card,.titem,.clink,.section-nav-btn').forEach(el=>{
    el.addEventListener('mouseenter',()=>{curRing.style.width='36px';curRing.style.height='36px';});
    el.addEventListener('mouseleave',()=>{curRing.style.width='24px';curRing.style.height='24px';});
  });
}

// ════════════════════════════════════════════════════
// EXP BAR
// ════════════════════════════════════════════════════
function initExpBar(){
  const expBar=document.getElementById('exp-bar');
  window.addEventListener('scroll',()=>{
    const pct=scrollY/(document.documentElement.scrollHeight-innerHeight)*100;
    expBar.style.width=Math.min(pct,100)+'%';
  },{passive:true});
}

// ════════════════════════════════════════════════════
// REVEAL ON SCROLL
// ════════════════════════════════════════════════════
function initReveal(){
  const rv=new IntersectionObserver(entries=>entries.forEach(e=>{
    if(e.isIntersecting){
      e.target.classList.add('in');
      e.target.querySelectorAll('.stat-fill').forEach(b=>{
        setTimeout(()=>b.style.width=(b.dataset.w||0)+'%',100);
      });
    }
  }),{threshold:.1});
  document.querySelectorAll('.reveal').forEach(el=>rv.observe(el));
}

// ════════════════════════════════════════════════════
