// ════════════════════════════════════════════════════
function showNotif(msg){
  const el=document.getElementById('notif');
  el.textContent=msg; el.classList.add('show');
  setTimeout(()=>el.classList.remove('show'),2200);
}

// ════════════════════════════════════════════════════
// CLICK PARTICLES
// ════════════════════════════════════════════════════
function initParticles(){
  const colors=['#b8f400','#7c3aed','#06b6d4','#ec4899'];
  document.addEventListener('click',e=>{
    for(let i=0;i<4;i++){
      const el=document.createElement('div');
      el.style.cssText=`position:fixed;left:${e.clientX}px;top:${e.clientY}px;width:5px;height:5px;background:${colors[i%4]};pointer-events:none;z-index:500;border-radius:50%;transition:all .5s ease-out;`;
      document.body.appendChild(el);
      const angle=Math.random()*Math.PI*2,dist=20+Math.random()*45;
      setTimeout(()=>{el.style.transform=`translate(${Math.cos(angle)*dist}px,${Math.sin(angle)*dist}px)`;el.style.opacity='0';},10);
      setTimeout(()=>el.remove(),580);
    }
  });
}

